function _storeReentryLock(uint8 _reentry) internal virtual {
    if (block.chainid == 1) {
        assembly {
            tstore(_REENTRY_SLOT, _reentry)
        }
    } else {
        __reentry = _reentry;
    }
}

function _loadReentryLock() internal view virtual returns (uint8 reentry_) {
    if (block.chainid == 1) {
        assembly {
            reentry_ := tload(_REENTRY_SLOT)
        }
    } else {
        reentry_ = __reentry;
    }
}
